@pytest.mark.django_db
class TestCreateOrder:
    def test_creates_order_with_valid_data(self, user, product):
        order = services.create_order(user=user, items=[{"product_id": product.id, "quantity": 2}])
        assert order.user == user
        assert order.status == "pending"

    def test_raises_for_insufficient_stock(self, user, product):
        product.stock = 1
        product.save()
        with pytest.raises(ValueError, match="Insufficient stock"):
            services.create_order(user=user, items=[{"product_id": product.id, "quantity": 10}])

@pytest.mark.django_db
class TestUserAPI:
    def test_list_requires_auth(self, api_client):
        response = api_client.get("/api/v1/users/")
        assert response.status_code == 401

    def test_list_returns_users(self, authenticated_client, user_factory):
        user_factory(email="a@b.com")
        response = authenticated_client.get("/api/v1/users/")
        assert response.status_code == 200
        assert len(response.data["results"]) >= 1

@pytest.mark.parametrize("password,valid", [
    ("ValidPass1!", True),
    ("short1!", False),
    ("NOLOWER1!", False),
    ("NoDigit!!", False),
])
def test_password_validation(password, valid):
    assert validate_password(password).is_valid == valid
